I'm using the current master with Python 3 support.

I have HSTS enabled on our domain so even our development subdomains have to use HTTPS. This is very easy to achieve by wrapping Django's runserver.

However HTTPS doesn't play well with django-websocket-redis during development (I would presume it's fine behind nginx). WebSockets can connect but as soon as data is received they disconnect due to bad headers. This seems to be because the WebSockets passed around by the WSGI handler are just instances of io.BufferedReader and have no concept of HTTPS.

It's very easy to get a HTTPS WebSocket server running with pywsgi from gevent and gevent-websocket (+ some Python 3 fixes) but then I still can't seem to get the django-websocket-redis main loop to work properly. The problem seems to be that the way django-redis-websocket juggles file descriptors doesn't work with how pywsgi juggles sockets. There also doesn't seem to be any way to detect disconnects.

Below is my current code:

    def _runserver():
        from django.core.handlers.wsgi import WSGIHandler as DjangoListener
        from django.conf import settings
        from gevent import select, signal as g_signal
        from gevent.pool import Pool
        from gevent.pywsgi import WSGIServer
        from geventwebsocket.handler import WebSocketHandler
        from geventwebsocket.exceptions import WebSocketError
        import signal
        from ws4redis.exceptions import WebSocketError as RedisError
        from ws4redis.wsgi_server import WebsocketWSGIServer as RedisListener


        class WebSocket:
            def __init__(self, ws):
                self._closed = False
                self.ws = ws

            def get_file_descriptor(self):
                return self.ws.stream.handler.socket.fileno()

            @property
            def closed(self):
                return self._closed

            def receive(self):
                if self._closed:
                    raise RedisError('Connection is already closed')
                try:
                    data = self.ws.receive()
                    if data is not None:
                        return data.encode('utf-8')
                except WebSocketError as e:
                    self.close()
                    raise RedisError(e)

            def flush(self):
                pass

            def send(self, message, binary=None):
                self.ws.send(message, binary)

            def close(self, code=1000, message=''):
                self.ws.close(code, message)
                self._closed = True


        class GeventListener(RedisListener):
            def upgrade_websocket(self, environ, start_response):
                return WebSocket(environ['wsgi.websocket'])

            def select(self, rlist, wlist, xlist, timeout=None):
                return select.select(rlist, wlist, xlist, timeout)


        g_listener = GeventListener()
        _websocket_url = getattr(settings, 'WEBSOCKET_URL')

        class Listener(DjangoListener):
            def __call__(self, environ, start_response):
                if _websocket_url and environ.get('PATH_INFO').startswith(_websocket_url):
                    return g_listener(environ, start_response)
                return super().__call__(environ, start_response)


        bind = ('0.0.0.0', 8080)
        server = WSGIServer(
            bind,
            Listener(),
            spawn=Pool(10),
            handler_class=WebSocketHandler,
            certfile='cert.pem',
            keyfile='key.pem'
        )

        def stop(signal):
            if server and server.started:
                server.stop()
            sys.exit(signal)

        g_signal(signal.SIGINT, stop, signal.SIGINT)
        g_signal(signal.SIGTERM, stop, signal.SIGTERM)

        print('Starting WebSocket Enabled Server on %s:%s' % bind)
        server.serve_forever()

