I am trying to write some custom casters for things like Glib::ustring and boost::uuids::uuid. I can't find any documentation for type casters, so I am trying to do this by looking at `cast.h`. My current code looks like this:

```c++
template <> class type_caster<boost::uuids::uuid> {
public:
    bool load(handle src, bool) {
        object temp;
        handle load_src = src;
        if (load_src.ptr()==Py_None) {
            value=nil_gen();
            return true;
        }
        if (PyUnicode_Check(load_src.ptr())) {
            temp = object(PyUnicode_AsASCIIString(load_src.ptr()), false);
            if (!temp) { PyErr_Clear(); return false; }  // UnicodeEncodeError
            load_src = temp;
        }
        char *buffer;
        ssize_t length;
        int err = PYBIND11_BYTES_AS_STRING_AND_SIZE(load_src.ptr(), &buffer, &length);
        if (err == -1) {
            PyErr_Clear();
            return false;
        }  // TypeError
        try {
            value=parse_uuid(buffer);
            success=true;
        } catch (const std::runtime_error &e) {
            return false;
        }
        return true;
    }

    static handle cast(const boost::uuids::uuid &src, return_value_policy /* policy */, handle /* parent */) {
        if (src.is_nil())
            return handle(Py_None).inc_ref();
        std::string s(boost::uuids::to_string(src));
        return PyUnicode_FromStringAndSize(s.c_str(), static_cast<Py_ssize_t>(s.length()));
    }

    PYBIND11_TYPE_CASTER(boost::uuids::uuid, _(PYBIND11_STRING_NAME));
protected:
    bool success = false;
};
```

But that is not quite perfect: when trying to assign an invalid uuid to a boost::uuids::uuid property the error message is not very helpful:

```
>>> a.uuid = uuid.uuid4()
Traceback (most recent call last):
  File "<stdin>", line 1, in <module>
TypeError: Incompatible function arguments. The following argument types are supported:
    1. (stylist.Article, str) -> NoneType
```

Is there a good way to generate a better error message here?

I am also wondering if there is a convenient way to allow any input that can be coerced to a string; i.e. automatically attempt to call src.__str__ if it exists?

## Issue description

The current implicit conversion system doesn't allow to specify conversion for pointer type arguments, even though the same call would work in c++ (see the code). 

The main problem seems to be that `pybind11`'s function type detection always assumes the base type (i.e. A) to be the exposed one. If there were a possibility to declare a `py::class_<A*>(m, "APtr")` and force the function to accept it instead of `A` (by specifying an attribute on `py::arg` for example) it would solve the problem without making the more common use case any more cumbersome.

## Reproducible example code

```c++
#include <pybind11/pybind11.h>
#include <iostream>

using namespace std;
namespace py = pybind11;

struct A {
  A(const A& a) = delete;
  explicit A(int value) : value(value) { };
  int value;
};

struct Container_of_A {
  A* a;
  // define conversion
  operator A* () { return this->a; }
};

int test1(A* a) {
  return a->value;
}

PYBIND11_MODULE(conversion, m) {
  // sanity check
  A a(10);
  Container_of_A cont = {&a};
  cout << "Test 2: " << test1(cont) << endl;
  py::class_<A>(m, "A")
    .def(py::init<int>());
  //.def(py::init<Container_of_A>) doesn't work, since you can't initalize an instance of A with a pointer
  py::class_<Container_of_A>(m, "Container_of_A")
    .def(py::init<A*>());
  py::implicitly_convertible<Container_of_A, A>();
  m.def("test1", &test1, py::return_value_policy::reference);
}
```

```python
#!/usr/bin/env python3
import conversion as conv

a = conv.A(10)
container = conv.Container_of_A(a)
print('Success 1: ', conv.test1(a))
print('Failure 1: ', conv.test1(container))
```
